func TestCookieHeaderFromAgentBrowserJSON_FiltersTargetDomain(t *testing.T) {
	input := []byte(`{
		"success": true,
		"data": {
			"cookies": [
				{"domain": ".harristeeter.com", "name": "session", "value": "abc"},
				{"domain": "www.harristeeter.com", "name": "loggedIn", "value": "true"},
				{"domain": ".example.com", "name": "ignore", "value": "nope"}
			]
		}
	}`)

	header, err := cookieHeaderFromAgentBrowserJSON(input, "https://www.harristeeter.com")
	if err != nil {
		t.Fatalf("cookieHeaderFromAgentBrowserJSON returned error: %v", err)
	}
	if !strings.Contains(header, "session=abc") {
		t.Fatalf("expected Harris Teeter cookie in header, got %q", header)
	}
	if !strings.Contains(header, "loggedIn=true") {
		t.Fatalf("expected www Harris Teeter cookie in header, got %q", header)
	}
	if strings.Contains(header, "ignore=nope") {
		t.Fatalf("expected non-target cookie to be filtered, got %q", header)
	}
}

func TestCookieHeaderFromAgentBrowserJSON_ReturnsAgentBrowserError(t *testing.T) {
	input := []byte(`{"success": false, "error": "not connected", "data": {"cookies": []}}`)

	_, err := cookieHeaderFromAgentBrowserJSON(input, "https://www.harristeeter.com")
	if err == nil {
		t.Fatal("expected error for failed agent-browser result")
	}
	if !strings.Contains(err.Error(), "not connected") {
		t.Fatalf("expected agent-browser error detail, got %v", err)
	}
}
